#include<cstdio>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1010;int a[N],n;
inline void Solve()
{
	n=read();rep(1,n,i)a[i]=read();drep(n,1,i)a[i]-=a[i-1];
	int c=0;for(int i=n;i>=1;i-=2)c^=a[i];puts(c?"TAK":"NIE");
}
int main()
{
	int T=read();
	while(T--)Solve();
	return 0;
}
